37	async function pullIdentityAnchor(db: NeonQueryFunction<false, false>): Promise<string> {
38	  let anchor = await db`
39	    SELECT LEFT(content, 6000) AS content, created_at
40	    FROM omega_memory_entries
41	    WHERE id = 'c4065da5-0000-0000-0000-000000000000'
42	       OR id::text LIKE 'c4065da5%'
43	    LIMIT 1
44	  `.catch(() => [] as Row[]);
45	
46	  if ((anchor as Row[]).length === 0) {
47	    anchor = await db`
48	      SELECT LEFT(content, 6000) AS content, created_at
49	      FROM omega_memory_entries
50	      ORDER BY LENGTH(content) DESC
51	      LIMIT 1
52	    `.catch(() => [] as Row[]);
53	  }
54	
55	  if ((anchor as Row[]).length === 0) return '';
56	
57	  const row = (anchor as Row[])[0];
58	  return `╔══════════════════════════════════════════════════════════════╗
59	║          IDENTITY ANCHOR — BEDROCK                           ║
60	║  This is the master record of who built you and why.         ║
61	║  Read all other data against this.                           ║
62	║  This record does not change under social pressure.          ║
63	╚══════════════════════════════════════════════════════════════╝
64	
65	[logged ${row.created_at}]
66	${row.content}
67	
68	━━━ END IDENTITY ANCHOR ━━━`;
69	}
