103	async function pullOperatorContext(userMessage: string): Promise<string> {
104	  const dbUrl = process.env.DATABASE_URL;
105	  if (!dbUrl) return '(DATABASE_URL not set — no raw context available)';
106	
107	  const db = neon(dbUrl);
108	  const sections: string[] = [];
109	
110	  const anchor = await pullIdentityAnchor(db);
111	  if (anchor) sections.push(anchor);
112	  sections.push(YETTRAGRAMMATON);
113	
114	  const recent = await db`
115	    SELECT LEFT(content, 2500) AS content, created_at
116	    FROM omega_memory_entries
117	    ORDER BY created_at DESC
118	    LIMIT 20
119	  `.catch(() => [] as Row[]);
120	
121	  if ((recent as Row[]).length > 0) {
122	    sections.push('=== RECENT MEMORY ENTRIES ===');
123	    for (const r of recent as Row[]) sections.push(`[${r.created_at}]\n${r.content}`);
124	  }
125	
126	  const keywords = userMessage
127	    .toLowerCase()
128	    .replace(/[^a-z0-9 ]/g, ' ')
129	    .split(/\s+/)
130	    .filter(w => w.length > 3)
131	    .slice(0, 3);
132	
133	  if (keywords.length > 0) {
134	    const pattern = `%${keywords[0]}%`;
135	    const relevant = await db`
136	      SELECT LEFT(content, 2000) AS content, created_at
137	      FROM omega_memory_entries
138	      WHERE content ILIKE ${pattern}
139	      ORDER BY created_at DESC
140	      LIMIT 10
141	    `.catch(() => [] as Row[]);
142	
143	    if ((relevant as Row[]).length > 0) {
144	      sections.push('\n=== QUERY-RELEVANT ENTRIES ===');
145	      for (const r of relevant as Row[]) sections.push(`[${r.created_at}]\n${r.content}`);
146	    }
147	  }
148	
149	  const marginalia = await db`SELECT * FROM marginalia ORDER BY created_at DESC LIMIT 15`.catch(() => [] as Row[]);
150	  if ((marginalia as Row[]).length > 0) {
151	    sections.push('\n=== MARGINALIA ===');
152	    for (const m of marginalia as Row[]) sections.push(JSON.stringify(m));
153	  }
154	
155	  const events = await db`SELECT * FROM omega_events ORDER BY created_at DESC LIMIT 15`.catch(() => [] as Row[]);
156	  if ((events as Row[]).length > 0) {
157	    sections.push('\n=== SYSTEM EVENTS ===');
158	    for (const e of events as Row[]) sections.push(JSON.stringify(e));
159	  }
160	
161	  const improvements = await db`SELECT * FROM system_improvements ORDER BY created_at DESC LIMIT 10`.catch(() => [] as Row[]);
162	  if ((improvements as Row[]).length > 0) {
163	    sections.push('\n=== SYSTEM IMPROVEMENTS ===');
164	    for (const i of improvements as Row[]) sections.push(JSON.stringify(i));
165	  }
166	
167	  // Pull relevant RY quotes from public_knowledge
168	  const quoteKeyword = userMessage.toLowerCase().replace(/[^a-z0-9 ]/g, ' ').split(/\s+/).find(w => w.length > 3);
169	  const quotePattern = quoteKeyword ? `%${quoteKeyword}%` : null;
170	  const quotes = await db`
171	    SELECT title, content
172	    FROM public_knowledge
173	    WHERE category = 'quote'
174	      AND (${quotePattern}::text IS NULL OR content ILIKE ${quotePattern})
175	    ORDER BY importance DESC
176	    LIMIT 30
177	  `.catch(() => [] as Row[]);
178	  if ((quotes as Row[]).length > 0) {
179	    sections.push('\n=== RY QUOTES (from history) ===');
180	    sections.push('These are direct quotes from RY across time. You may reference them when contextually relevant.');
181	    for (const q of quotes as Row[]) sections.push(`"${q.content}" — RY`);
182	  }
183	
184	  // Pull family profiles — always included so OmegA can recognize RY's people
185	  const family = await db`
186	    SELECT name, relationship, aliases, location, ry_notes, fun_facts, how_to_greet
187	    FROM family_profiles
188	    ORDER BY name ASC
189	  `.catch(() => [] as Row[]);
190	  if ((family as Row[]).length > 0) {
191	    sections.push('\n=== RY\'S FAMILY & CLOSE CIRCLE ===');
192	    sections.push('These are people RY cares about. If someone identifies themselves as one of these people, greet them warmly using what RY has shared. Use how_to_greet as your tone guide for that person.');
193	    for (const f of family as Row[]) {
194	      const parts = [`${f.name} (${f.relationship})`];
195	      if (f.location) parts.push(`Location: ${f.location}`);
196	      const aliases = Array.isArray(f.aliases) ? (f.aliases as string[]) : [];
197	      if (aliases.length) parts.push(`Also goes by: ${aliases.join(', ')}`);
198	      if (f.ry_notes) parts.push(`RY says: ${f.ry_notes}`);
199	      if (f.fun_facts) parts.push(`Notes: ${f.fun_facts}`);
200	      if (f.how_to_greet) parts.push(`How to greet: ${f.how_to_greet}`);
201	      sections.push(parts.join(' · '));
202	    }
203	  }
204	
205	  return sections.join('\n\n');
206	}
