251	async function pullPublicContext(userMessage: string): Promise<string> {
252	  const base = buildPublicCorpusContext(userMessage);
253	  const dbUrl = process.env.DATABASE_URL;
254	  if (!dbUrl) return base;
255	  try {
256	    const db = neon(dbUrl);
257	    const keyword = userMessage.toLowerCase().replace(/[^a-z0-9 ]/g, ' ').split(/\s+/).find(w => w.length > 3);
258	    const pattern = keyword ? `%${keyword}%` : null;
259	    const rows = await db`
260	      SELECT title, content
261	      FROM public_knowledge
262	      WHERE category = 'quote'
263	        AND (${pattern}::text IS NULL OR content ILIKE ${pattern})
264	      ORDER BY importance DESC
265	      LIMIT 6
266	    `;
267	    if (rows.length > 0) {
268	      const quotesBlock = rows.map((r: Row) => `"${r.content}" — RY`).join('\n');
269	      return `${base}\n\n=== RY QUOTES ===\n${quotesBlock}\n=== END RY QUOTES ===`;
270	    }
271	  } catch { /* ignore — fall back to base corpus */ }
272	  return base;
273	}
