275	// ── Privacy scrubber (public mode only) ───────────────────────────────────────
276	// Belt-and-suspenders: catch private data patterns before they reach public clients.
277	// The system prompt does the primary filtering; this catches anything that slips through.
278	function scrubPrivateData(text: string): string {
279	  return text
280	    // phone numbers (US and international)
281	    .replace(/\b(\+?1[-.\s]?)?\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4}\b/g, '[REDACTED-PHONE]')
282	    // email addresses
283	    .replace(/\b[A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Za-z]{2,}\b/g, '[REDACTED-EMAIL]')
284	    // SSN-shaped patterns
285	    .replace(/\b\d{3}-\d{2}-\d{4}\b/g, '[REDACTED-ID]')
286	    // legal case numbers (common US formats)
287	    .replace(/\b(case\s*#?\s*\d[\d\-\/]{4,}|\d{2}-[A-Z]{2}-\d{4,})\b/gi, '[REDACTED-CASE]')
288	    // street addresses (number + street keyword)
289	    .replace(/\b\d{1,5}\s+\w+\s+(st|ave|blvd|dr|rd|ln|way|ct|pl|street|avenue|boulevard|drive|road|lane|court|place)\b[^,\n]*/gi, '[REDACTED-ADDRESS]');
290	}
