294	async function loadSessionHistory(
295	  db: NeonQueryFunction<false, false>,
296	  sessionId: string,
297	): Promise<Msg[]> {
298	  const rows = await db`
299	    SELECT role, content
300	    FROM omega_chat_messages
301	    WHERE session_id = ${sessionId}
302	    ORDER BY created_at ASC
303	  `.catch(() => [] as Row[]);
304	
305	  return (rows as Row[])
306	    .filter((row) => row.role === 'user' || row.role === 'omega')
307	    .map((row) => ({ role: row.role as 'user' | 'omega', text: String(row.content ?? '') }));
308	}
