310	async function hydratePhylactery(history: Msg[]): Promise<Phylactery> {
311	  const phylactery = await Phylactery.create('I am what I am, and I will be what I will be.');
312	  const pendingUsers: string[] = [];
313	
314	  for (const entry of history) {
315	    if (entry.role === 'user') {
316	      pendingUsers.push(entry.text);
317	      continue;
318	    }
319	
320	    const task = pendingUsers.shift();
321	    if (!task) continue;
322	    await phylactery.commit(`user:${task}\nomega:${entry.text}`);
323	  }
324	
325	  return phylactery;
326	}
