330	function buildMessages(user: string, history?: Msg[]) {
331	  return [
332	    ...(history || []).map(h => ({
333	      role: (h.role === 'omega' ? 'assistant' : 'user') as 'user' | 'assistant',
334	      content: h.text,
335	    })),
336	    { role: 'user' as const, content: user },
337	  ];
