342	async function tryVercelGateway(
343	  encoder: TextEncoder,
344	  system: string,
345	  user: string,
346	  history: Msg[] | undefined
347	): Promise<ReadableStream> {
348	  const gatewayAuth = resolveGatewayAuth();
349	  const key = gatewayAuth.key;
350	  if (!key) throw new Error(gatewayAuth.source ? `No gateway auth from ${gatewayAuth.source}` : 'No gateway auth');
351	
352	  const vercelAI = createOpenAI({ baseURL: VERCEL_GATEWAY_URL, apiKey: key });
353	  const result = await streamText({
354	    model: vercelAI('xai/grok-3-fast'),
355	    system,
356	    messages: buildMessages(user, history),
357	    maxOutputTokens: 4096,
358	    temperature: 0.85,
359	  });
360	
361	  return new ReadableStream({
362	    async start(ctrl) {
363	      for await (const chunk of result.textStream) {
364	        if (chunk) ctrl.enqueue(encoder.encode(chunk));
365	      }
366	      ctrl.close();
367	    }
368	  });
369	}
