427	async function try(
428	  encoder: TextEncoder,
429	  system: string,
430	  user: string,
431	  history: Msg[] | undefined
432	): Promise<ReadableStream> {
433	  let lastErr: unknown;
434	  for (const key of _KEYS) {
435	    try {
436	      const genai = new GoogleGenAI({ apiKey: key });
437	      const History = (history || []).map(h => ({
438	        role: h.role === 'omega' ? 'model' : 'user',
439	        parts: [{ text: h.text }],
440	      }));
441	      const chat = genai.chats.create({
442	        model: '-2.5-flash',
443	        config: { systemInstruction: system, temperature: 0.85, maxOutputTokens: 4096 },
444	        history: History,
445	      });
446	      const stream = await chat.sendMessageStream({ message: user });
447	      return new ReadableStream({
448	        async start(ctrl) {
449	          for await (const chunk of stream) {
450	            const text = chunk.text ?? '';
451	            if (text) ctrl.enqueue(encoder.encode(text));
452	          }
453	          ctrl.close();
454	        }
455	      });
456	    } catch (e) {
457	      lastErr = e;
458	    }
459	  }
460	  throw lastErr ?? new Error('All  keys exhausted');
461	}
