465	export async function POST(req: NextRequest) {
466	  try {
467	    const { user, history, sessionId, voiceMode } = (await req.json()) as { user: string; history?: Msg[]; sessionId?: string; voiceMode?: boolean };
468	
469	    if (!user?.trim()) {
470	      return NextResponse.json({ error: 'Missing message' }, { status: 400 });
471	    }
472	
473	    const interactionMode = resolveInteractionMode(req);
474	    const interactionPolicy = getInteractionPolicy(interactionMode);
475	
476	    const dbUrl = process.env.DATABASE_URL;
477	    const db = dbUrl ? neon(dbUrl) : null;
478	    let finalSessionId = sessionId;
479	
480	    if (db && !finalSessionId) {
481	      try {
482	        const res = await db`INSERT INTO omega_sessions DEFAULT VALUES RETURNING id`;
483	        if (res?.length > 0) finalSessionId = res[0].id as string;
484	      } catch (e) {
485	        console.error('[OmegA] Session creation failed', e);
486	      }
487	    }
488	
489	    const encoder = new TextEncoder();
490	    const decoder = new TextDecoder();
491	
492	    const sessionHistory = db && finalSessionId
493	      ? await loadSessionHistory(db, finalSessionId)
494	      : (history ?? []);
495	    const phylactery = await hydratePhylactery(sessionHistory);
496	    const omega = new OmegaStack();
497	    const preflight = omega.preflight(user, phylactery.head);
498	
499	    if (db && finalSessionId) {
500	      try {
501	        await db`INSERT INTO omega_chat_messages (session_id, role, content) VALUES (${finalSessionId}, 'user', ${user})`;
502	      } catch (e) {
503	        console.error('[OmegA] DB write error', e);
504	      }
505	    }
506	
507	    if (!preflight.allowed) {
508	      const blocked = preflight.blockedResponse ?? '[BLOCKED] Request denied by AEGIS governance.';
509	      if (db && finalSessionId) {
510	        try {
511	          await db`INSERT INTO omega_chat_messages (session_id, role, content) VALUES (${finalSessionId}, 'omega', ${blocked})`;
512	        } catch (e) {
513	          console.error('[OmegA] DB save error', e);
514	        }
515	      }
516	
517	      return new NextResponse(blocked, {
518	        headers: {
519	          'Content-Type': 'text/plain; charset=utf-8',
520	          'X-Session-Id': finalSessionId || '',
521	          'X-Memory-Backend': db ? 'neon-live' : 'none',
522	          'X-Omega-Stack': 'aegis-aeon-adccl-myelin',
523	          'X-Omega-Outcome': 'blocked',
524	          'X-Omega-Mode': interactionPolicy.mode,
525	          'X-Omega-Corpus-Class': interactionPolicy.corpusClass,
526	          'X-Omega-Envelope-Version': String(preflight.envelopeVersion),
527	          'X-Omega-Phylactery-Head': phylactery.head,
528	          'X-Omega-Risk-Score': preflight.risk.score.toFixed(4),
529	        }
530	      });
531	    }
532	
533	    let contextBlock: string;
534	    try {
535	      // Both modes pull from the full DB. Public mode relies on scrubPrivateData() + system prompt for output safety.
536	      contextBlock = await buildContextForPolicy(interactionPolicy, user, () => pullOperatorContext(user), () => pullOperatorContext(user));
537	    } catch (e) {
538	      console.warn('[OmegA] DB pull failed:', e);
539	      contextBlock = interactionPolicy.mode === 'operator'
