import { neon } from '@neondatabase/serverless';
import { NextRequest, NextResponse } from 'next/server';
import { resolveInteractionMode } from '@/lib/omega/policy';
import { safeErrorMessage } from '@/lib/hardening';

export async function GET(req: NextRequest) {
  // Sessions list is operator-only — contains all conversation history (#16, #17)
  const mode = resolveInteractionMode(req);
  if (mode !== 'operator') {
    return NextResponse.json({ error: 'Unauthorised' }, { status: 401 });
  }

  try {
    const dbUrl = process.env.DATABASE_URL;
    if (!dbUrl) return NextResponse.json({ error: safeErrorMessage(500) }, { status: 500 });

    const db = neon(dbUrl);
    const sessions = await db`
      SELECT s.id, s.created_at,
             (SELECT content FROM omega_chat_messages
              WHERE session_id = s.id AND role = 'user'
              ORDER BY created_at ASC LIMIT 1) AS preview
      FROM omega_sessions s
      ORDER BY s.updated_at DESC
      LIMIT 20
    `;

    return NextResponse.json(sessions);
  } catch (err) {
    console.error('[OmegA sessions] Failed to fetch sessions', err);
    return NextResponse.json({ error: String(err) }, { status: 500 });
  }
}

