'use client';

import { useState, useRef, useEffect, useCallback } from 'react';
import s from './InputArea.module.css';

// Mirror of LIMITS.MAX_MESSAGE_CHARS in hardening.ts — keep in sync
const MAX_CHARS = 4_000;
// Warn when within this many chars of the limit
const WARN_THRESHOLD = 3_500;

interface InputAreaProps {
  onSend: (text: string) => void;
  disabled: boolean;
  autoFocus: boolean;
}

export default function InputArea({ onSend, disabled, autoFocus }: InputAreaProps) {
  const [value, setValue] = useState('');
  const ref = useRef<HTMLTextAreaElement>(null);
  const inputId = 'omega-chat-input';

  const resize = useCallback(() => {
    const el = ref.current;
    if (!el) return;
    el.style.height = 'auto';
    const lineH = parseFloat(getComputedStyle(el).lineHeight) || 22;
    const maxH = lineH * 6;
    el.style.height = `${Math.min(el.scrollHeight, maxH)}px`;
  }, []);

  useEffect(() => {
    if (autoFocus && !disabled) ref.current?.focus();
  }, [autoFocus, disabled]);

  const send = () => {
    const text = value.trim();
    if (!text || disabled || value.length > MAX_CHARS) return;
    onSend(text);
    setValue('');
    requestAnimationFrame(() => {
      if (ref.current) ref.current.style.height = 'auto';
    });
  };

  const handleKey = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      send();
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    // Hard cap at MAX_CHARS (#5 — prevent oversized inputs reaching server)
    if (e.target.value.length <= MAX_CHARS) {
      setValue(e.target.value);
    }
    resize();
  };

  const atLimit = value.length >= MAX_CHARS;
  const nearLimit = value.length >= WARN_THRESHOLD && !atLimit;
  const showCount = value.length > 0;

  return (
    <div className={s.wrap}>
      {/* Screen-reader label (#29) */}
      <label htmlFor={inputId} className={s.srOnly}>
        Message OmegA
      </label>
      <div
        className={`${s.bar} ${value.trim() ? s.hasInput : ''} ${disabled ? s.disabled : ''} ${atLimit ? s.atLimit : ''}`}
        role="group"
        aria-label="Chat input area"
      >
        <textarea
          id={inputId}
          ref={ref}
          className={s.textarea}
          value={value}
          onChange={handleChange}
          onKeyDown={handleKey}
          placeholder="Ask OmegA anything..."
          rows={1}
          disabled={disabled}
          autoFocus={autoFocus}
          maxLength={MAX_CHARS}
          aria-label="Type your message"
          aria-describedby={showCount ? 'omega-char-count' : undefined}
          aria-invalid={atLimit ? 'true' : undefined}
        />
        <div className={s.meta}>
          {showCount && (
            <span
              id="omega-char-count"
              className={`${s.charCount} ${nearLimit ? s.charWarn : ''} ${atLimit ? s.charLimit : ''}`}
              aria-live="polite"
              aria-label={`${value.length} of ${MAX_CHARS} characters`}
            >
              {value.length}{atLimit ? ` / ${MAX_CHARS}` : ''}
            </span>
          )}
        </div>
        <button
          className={`${s.sendBtn} ${value.trim() && !atLimit ? s.glow : ''}`}
          onClick={send}
          disabled={!value.trim() || disabled || atLimit}
          aria-label="Send message to OmegA"
          type="button"
        >
          Ω
        </button>
      </div>
      {atLimit && (
        <p className={s.limitMsg} role="alert" aria-live="assertive">
          Message limit reached ({MAX_CHARS.toLocaleString()} chars). Shorten your message to send.
        </p>
      )}
    </div>
  );
}

