1	import { safeErrorMessage } from '@/lib/hardening';
2	import { NextRequest, NextResponse } from 'next/server';
3	
4	/**
5	 * OmegA STT — Speech-to-Text endpoint
6	 * Accepts: multipart/form-data with field "audio" (webm/wav/mp3/m4a)
7	 * Returns: { text: string }
8	 * Uses OpenAI Whisper API
9	 */
10	export async function POST(req: NextRequest) {
11	  try {
12	    const key = process.env.OPENAI_API_KEY;
13	    if (!key) {
14	      return NextResponse.json({ error: 'STT unavailable — no API key' }, { status: 503 });
15	    }
16	
17	    const formData = await req.formData();
18	    const audioFile = formData.get('audio') as File | null;
19	
20	    if (!audioFile) {
21	      return NextResponse.json({ error: 'No audio file provided' }, { status: 400 });
22	    }
23	
24	    // Forward to OpenAI Whisper
25	    const whisperForm = new FormData();
26	    whisperForm.append('file', audioFile, audioFile.name || 'audio.wav');
27	    whisperForm.append('model', 'whisper-1');
28	    whisperForm.append('language', 'en');
29	
30	    const res = await fetch('https://api.openai.com/v1/audio/transcriptions', {
31	      method: 'POST',
32	      headers: { Authorization: `Bearer ${key}` },
33	      body: whisperForm,
34	    });
35	
36	    if (!res.ok) {
37	      const err = await res.text();
38	      console.error('[OmegA STT] Whisper error:', err);
39	      return NextResponse.json({ error: 'Transcription failed' }, { status: 502 });
40	    }
41	
42	    const data = await res.json();
43	    return NextResponse.json({ text: data.text ?? '' });
44	  } catch (err) {
45	    console.error('[OmegA STT]', err);
46	    return NextResponse.json({ error: safeErrorMessage(500, err) }, { status: 500 });
47	  }
48	}
