import { safeErrorMessage } from '@/lib/hardening';
import { NextRequest, NextResponse } from 'next/server';

/* ── ElevenLabs (primary) ── */
const ELEVEN_KEY = process.env.ELEVENLABS_API_KEY ?? '';
const ELEVEN_VOICE_ID = 'onwK4e9ZLuTAKqWW03F9'; // "Daniel" — deep, authoritative, conversational
const ELEVEN_MODEL = 'eleven_turbo_v2_5'; // lowest latency, optimized for conversational AI

/* ──  (fallback) ── */
const _KEYS = [
  process.env._API_KEY_4,
  process.env._API_KEY_2,
  process.env._API_KEY,
].filter(Boolean) as string[];

const TTS_MODEL = '-2.5-flash-preview-tts';
const TTS_VOICE = 'Charon';

async function elevenLabsTTS(text: string): Promise<Buffer | null> {
  if (!ELEVEN_KEY) return null;

  try {
    const res = await fetch(
      `https://api.elevenlabs.io/v1/text-to-speech/${ELEVEN_VOICE_ID}`,
      {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'xi-api-key': ELEVEN_KEY,
        },
        body: JSON.stringify({
          text,
          model_id: ELEVEN_MODEL,
          voice_settings: {
            stability: 0.5,
            similarity_boost: 0.75,
            style: 0.4,
            use_speaker_boost: true,
          },
        }),
      }
    );

    if (!res.ok) {
      console.warn(`[TTS] ElevenLabs failed — status ${res.status}`);
      return null;
    }

    const arrayBuf = await res.arrayBuffer();
    return Buffer.from(arrayBuf);
  } catch (e) {
    console.warn('[TTS] ElevenLabs error:', e);
    return null;
  }
}

async function TTS(text: string): Promise<{ wav: Buffer } | null> {
  for (const key of _KEYS) {
    try {
      const res = await fetch(
        `https://generativelanguage.googleapis.com/v1beta/models/${TTS_MODEL}:generateContent?key=${key}`,
        {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            contents: [{ parts: [{ text }] }],
            generationConfig: {
              responseModalities: ['AUDIO'],
              speechConfig: {
                voiceConfig: { prebuiltVoiceConfig: { voiceName: TTS_VOICE } },
              },
            },
          }),
        }
      );

      if (!res.ok) { console.warn(`[TTS]  key failed — status ${res.status}`); continue; }

      const data = await res.json();
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const part = data.candidates?.[0]?.content?.parts?.find((p: any) => p.inlineData);
      if (!part?.inlineData?.data) continue;

      const pcm = Buffer.from(part.inlineData.data, 'base64');
      const wav = pcmToWav(pcm);
      return { wav };
    } catch (e) {
      console.warn('[TTS]  key error:', e);
    }
  }
  return null;
}

function pcmToWav(pcmBuffer: Buffer, sampleRate = 24000, channels = 1, bitDepth = 16): Buffer {
  const byteRate = sampleRate * channels * (bitDepth / 8);
  const blockAlign = channels * (bitDepth / 8);
  const header = Buffer.alloc(44);
  header.write('RIFF', 0);
  header.writeUInt32LE(36 + pcmBuffer.length, 4);
  header.write('WAVE', 8);
  header.write('fmt ', 12);
  header.writeUInt32LE(16, 16);
  header.writeUInt16LE(1, 20);
  header.writeUInt16LE(channels, 22);
  header.writeUInt32LE(sampleRate, 24);
  header.writeUInt32LE(byteRate, 28);
  header.writeUInt16LE(blockAlign, 32);
  header.writeUInt16LE(bitDepth, 34);
  header.write('data', 36);
  header.writeUInt32LE(pcmBuffer.length, 40);
  return Buffer.concat([header, pcmBuffer]);
}

export async function POST(req: NextRequest) {
  try {
    const { text } = (await req.json()) as { text?: string };
    if (!text?.trim()) return NextResponse.json({ error: 'No text provided' }, { status: 400 });

    const safeText = text.slice(0, 2000);

    // Try ElevenLabs first — returns mp3 directly
    const elevenAudio = await elevenLabsTTS(safeText);
    if (elevenAudio) {
      const b64 = elevenAudio.toString('base64');
      return NextResponse.json({ audio: b64, mimeType: 'audio/mpeg', provider: 'elevenlabs' });
    }

    // Fallback to  TTS — returns wav
    const Result = await TTS(safeText);
    if (Result) {
      const b64 = Result.wav.toString('base64');
      return NextResponse.json({ audio: b64, mimeType: 'audio/wav', provider: '' });
    }

    return NextResponse.json({ error: 'TTS unavailable — all providers failed' }, { status: 503 });
  } catch (err) {
    return NextResponse.json({ error: safeErrorMessage(500, err) }, { status: 500 });
  }
}

