const TTS_TIMEOUT_MS = 20_000;

async function elevenLabsTTSWithTimeout(text: string): Promise<Buffer | null> {
  const cb = getCircuitBreaker('elevenlabs');
  if (cb.isOpen) return null;
  try {
    const result = await withRetryBackoff(
      async () => {
        const controller = new AbortController();
        const timer = setTimeout(() => controller.abort(), TTS_TIMEOUT_MS);
        try {
          const res = await fetch(
            `https://api.elevenlabs.io/v1/text-to-speech/${ELEVEN_VOICE_ID}`,
            {
              method: 'POST',
              headers: { 'Content-Type': 'application/json', 'xi-api-key': ELEVEN_KEY },
              body: JSON.stringify({
                text,
                model_id: ELEVEN_MODEL,
                voice_settings: { stability: 0.5, similarity_boost: 0.75, style: 0.4, use_speaker_boost: true },
              }),
              signal: controller.signal,
            },
          );
          if (!res.ok) throw new Error(`ElevenLabs ${res.status}`);
          return Buffer.from(await res.arrayBuffer());
        } finally {
          clearTimeout(timer);
        }
      },
      { maxAttempts: 2, baseDelayMs: 300 },
    );
    cb.recordSuccess();
    return result;
  } catch (e) {
    cb.recordFailure();
    console.warn('[TTS] ElevenLabs failed:', e);
    return null;
  }
}

export async function POST(req: NextRequest) {
  const correlationId = req.headers.get(CORRELATION_HEADER) ?? generateCorrelationId();

  // Rate limit — TTS is expensive (#V9, #V1)
  const mode = resolveInteractionMode(req);
  const isOperator = mode === 'operator';
  const clientIp = req.headers.get('x-forwarded-for')?.split(',')[0].trim() ?? 'unknown';
  const rateResult = checkTTSRateLimit(clientIp, isOperator);
  if (!rateResult.allowed) {
    return NextResponse.json(
      { error: safeErrorMessage(429) },
      { status: 429, headers: { 'Retry-After': String(Math.ceil((rateResult.resetAt - Date.now()) / 1000)) } },
    );
  }

  try {
    const body = await req.json() as { text?: string };
    if (!body?.text?.trim()) return NextResponse.json({ error: 'No text provided' }, { status: 400 });

    // Strip markdown before synthesis — TTS reads `**bold**` literally (#V6)
    const safeText = stripMarkdownForVoice(body.text);

    if (!safeText) return NextResponse.json({ error: 'No speakable text after processing' }, { status: 400 });

    // Try ElevenLabs first (with circuit breaker + timeout)
    const elevenAudio = await elevenLabsTTSWithTimeout(safeText);
    if (elevenAudio) {
      return NextResponse.json(
        { audio: elevenAudio.toString('base64'), mimeType: 'audio/mpeg', provider: 'elevenlabs', correlationId },
        { headers: { [CORRELATION_HEADER]: correlationId } },
      );
    }

    // Fallback to  TTS
    const Result = await TTS(safeText);
    if (Result) {
      return NextResponse.json(
        { audio: Result.wav.toString('base64'), mimeType: 'audio/wav', provider: '', correlationId },
        { headers: { [CORRELATION_HEADER]: correlationId } },
      );
    }

    return NextResponse.json({ error: 'TTS unavailable — all providers failed' }, { status: 503 });
  } catch (err) {
    return NextResponse.json({ error: safeErrorMessage(500, err) }, { status: 500 });
  }
}

