        clearTimeout(t);
        if (silenceTimerRef.current) clearTimeout(silenceTimerRef.current);
        if (mediaRecorderRef.current?.state === 'recording') mediaRecorderRef.current.stop();
        mutedRef.current = true;
        stopMicAnalyzer();
        clearFollowUp();
      };
